import type * as React from 'react';
export type RcMenuMode = 'horizontal' | 'vertical' | 'inline';
export type BuiltinPlacements = Record<string, any>;
export type TriggerSubMenuAction = 'click' | 'hover';
export interface RenderIconInfo {
    isSelected?: boolean;
    isOpen?: boolean;
    isSubMenu?: boolean;
    disabled?: boolean;
}
export type RenderIconType = React.ReactNode | ((props: RenderIconInfo) => React.ReactNode);
export interface RcMenuInfo {
    /**
     * menuItem 的唯一标识
     */
    key: string;
    /**
     * key 组成的路径
     */
    keyPath: string[];
    /** @deprecated This will not support in future. You should avoid to use this */
    item: React.ReactInstance;
    /**
     * 事件
     */
    domEvent: React.MouseEvent<HTMLElement> | React.KeyboardEvent<HTMLElement>;
}
export interface MenuTitleInfo {
    key: string;
    domEvent: React.MouseEvent<HTMLElement> | React.KeyboardEvent<HTMLElement>;
}
export type MenuHoverEventHandler = (info: {
    key: string;
    domEvent: React.MouseEvent<HTMLElement>;
}) => void;
/**
 * @docgen
 * @public
 */
export interface MenuSelectInfo extends RcMenuInfo {
    selectedKeys: string[];
}
export type MenuSelectEventHandler = (info: MenuSelectInfo) => void;
export type MenuClickEventHandler = (info: RcMenuInfo) => void;
